const reminders = $('Fetch Julian reminders').first().json;
const allCandidates = $('Fetch new discovery candidates').all().map(i => i.json);

// ── Julian's matching config (from profile) ─────────────────
const TARGET_KEYWORDS = [
  'data science', 'machine learning', 'ml engineer', 'data engineer',
  'ai engineer', 'data pipeline', 'aws', 'pyspark', 'python',
  'internship', 'practicante', 'trainee', 'junior', 'nlp', 'llm',
  'mlops', 'deep learning', 'analytics engineer', 'data intern',
  'software engineer intern', 'platform engineer', 'pytorch', 'spark'
];

const EXCLUDE_KEYWORDS = [
  'senior', 'lead', 'manager', 'full-time only',
  'java only', 'php', '.net', 'frontend only', 'ios', 'android'
];

const PREFERRED_STACK = [
  'python', 'aws', 'pytorch', 'pyspark', 'fastapi',
  'postgresql', 'terraform', 'docker', 'scikit-learn', 'xgboost'
];

const EXCLUDED_COMPANIES = ['tritone analytics'];
const MIN_SCORE = 65;

// ── Oracle GenO deadline awareness ──────────────────────────
const ORACLE_ASSESSMENT = new Date('2026-07-24');
const ORACLE_RESULTS    = new Date('2026-07-31');
const now = new Date();
const daysToAssessment = Math.ceil((ORACLE_ASSESSMENT - now) / 86400000);
const daysToResults    = Math.ceil((ORACLE_RESULTS - now) / 86400000);

// ── Candidate scoring ────────────────────────────────────────
const scoreCandidate = (c) => {
  const text  = `${c.detected_job_title || ''} ${c.company_name || ''}`.toLowerCase();
  const comp  = (c.company_name || '').toLowerCase();

  if (EXCLUDED_COMPANIES.some(x => comp.includes(x))) return -1;
  if (EXCLUDE_KEYWORDS.some(kw => text.includes(kw))) return -1;
  if (!TARGET_KEYWORDS.some(kw => text.includes(kw))) return 0;

  let score = 50;
  score += PREFERRED_STACK.filter(s => text.includes(s)).length * 10;
  score += (c.confidence_score || 0) * 20;
  return Math.min(score, 100);
};

const scoredCandidates = allCandidates
  .map(c => ({ ...c, _score: scoreCandidate(c) }))
  .filter(c => c._score >= MIN_SCORE)
  .sort((a, b) => b._score - a._score);

// ── Build Telegram message ───────────────────────────────────
const hour = now.getHours();
const greeting = hour < 12 ? '☀️ Buenos días' : hour < 18 ? '🌤 Buenas tardes' : '🌙 Buenas noches';

let msg = `${greeting}, Julian.\n`;
msg += `🤖 *JARVIS — Pipeline Report*\n`;
msg += `📅 ${now.toLocaleDateString('es-CO', {weekday:'long', day:'numeric', month:'long'})}\n\n`;

// Oracle alert
if (daysToAssessment >= 0 && daysToAssessment <= 7) {
  msg += `⚠️ *Oracle GenO — Assessment Center en ${daysToAssessment} días* (${ORACLE_ASSESSMENT.toLocaleDateString('es-CO')})\n`;
  msg += `📍 Presencial 9AM–5PM, Oracle Bogotá\n\n`;
} else if (daysToResults >= 0 && daysToResults <= 3) {
  msg += `📬 *Oracle GenO — Resultados en ${daysToResults} días*\n\n`;
}

// Application reminders (only Julian's)
const appReminders = Array.isArray(reminders.top_items)
  ? reminders.top_items.filter(r => r.related_entity_type === 'application')
  : [];

if (appReminders.length > 0) {
  msg += `📋 *Aplicaciones con acción pendiente:*\n`;
  for (const r of appReminders.slice(0, 5)) {
    const icon = r.severity === 'high' ? '🔴' : r.severity === 'medium' ? '🟡' : '🟢';
    msg += `${icon} ${r.description}\n`;
  }
  msg += '\n';
} else {
  msg += `✅ Sin acciones pendientes en tus aplicaciones.\n\n`;
}

// Matched candidates
if (scoredCandidates.length > 0) {
  msg += `🎯 *${scoredCandidates.length} match${scoredCandidates.length > 1 ? 'es' : ''} ML/AI para ti:*\n`;
  for (const c of scoredCandidates.slice(0, 8)) {
    const icon = c._score >= 80 ? '🟢' : c._score >= 65 ? '🟡' : '🔵';
    const title = c.detected_job_title || 'Posición';
    const company = c.company_name || 'Empresa';
    const url = c.detected_job_url ? `\n   [Ver oferta](${c.detected_job_url})` : '';
    msg += `${icon} *${company}*: ${title} _(score: ${Math.round(c._score)})_${url}\n`;
  }
  if (scoredCandidates.length > 8) {
    msg += `_...${scoredCandidates.length - 8} más en el dashboard_\n`;
  }
  msg += `\n👉 [Revisar candidatos](http://localhost:3001/discovery)`;
} else {
  msg += `🔍 Sin nuevos matches ML/AI hoy (score mínimo: ${MIN_SCORE}).\n`;
  msg += `👉 [Ver dashboard](http://localhost:3001)`;
}

const oracleUrgent = daysToAssessment >= 0 && daysToAssessment <= 7;
const hasAnything  = appReminders.length > 0 || scoredCandidates.length > 0 || oracleUrgent;

return [{
  json: {
    message: msg,
    should_notify: hasAnything,
    ml_matches_count: scoredCandidates.length,
    app_reminders_count: appReminders.length,
    oracle_days_remaining: daysToAssessment,
    total_candidates_checked: allCandidates.length
  }
}];
